29:     if (streak <= 0) return false;
30:     if (streak == 1) return true;
31:     if (streak % 3 == 0) return true;
32:     if (streak % 7 == 0) return true;
33:     if (streak % 14 == 0) return true;
34:     if (streak % 30 == 0) return true;
35:     if (streak % 100 == 0) return true;
36:     return false;
37:   }
38: 
39:   String getMilestoneMessage(int streak) {
40:     if (streak == 1) return 'First day! Let\'s start a streak! 🔥';
41:     if (streak == 3) return '3-day streak! Keep going! 🔥🔥🔥';
42:     if (streak == 7) return 'One week! You\'re on fire! 🔥🔥🔥🔥🔥🔥🔥';
43:     if (streak == 14) return 'Two weeks strong! Amazing dedication! 💪';
44:     if (streak == 30) return '30-day streak! You\'re a champion! 🏆';
45:     if (streak == 100) return '100-day streak! Legendary! 👑';
46:     if (streak % 30 == 0) return '\$streak-day streak! Unstoppable! 🚀';
47:     if (streak % 7 == 0) return '\$streak-day streak! Keep it up! ⭐';
48:     return 'Streak: \$streak days! 🔥';
49:   }
50: 
51:   // ── Daily Streak Check ──
52: 
53:   bool shouldResetStreak() {
54:     final progress = _progressRepository.getProgress();
55:     if (progress == null) return false;
56: 
57:     final now = DateTime.now();
58:     final lastActive = progress.lastActiveDate;
59:     final today = DateTime(now.year, now.month, now.day);
60:     final lastDay = DateTime(lastActive.year, lastActive.month, lastActive.day);
61:     
62:     return today.difference(lastDay).inDays >= 2;
63:   }
64: 
