66:     final progress = _progressRepository.getProgress();
67:     
68:     // First-time user — initialize streak to 1
69:     if (progress == null) {
70:       await _progressRepository.incrementStreak(); // 0 -> 1
71:       await _progressRepository.updateLastActiveDate(DateTime.now());
72:       await _progressRepository.incrementTotalActiveDays();
73:       return 1;
74:     }
75: 
76:     final now = DateTime.now();
77:     final lastActive = progress.lastActiveDate;
78:     final today = DateTime(now.year, now.month, now.day);
79:     final lastActiveDay = DateTime(lastActive.year, lastActive.month, lastActive.day);
80:     final daysDifference = today.difference(lastActiveDay).inDays;
81: 
82:     if (daysDifference >= 2) {
83:       // Streak broken — reset to 1
84:       await _progressRepository.resetStreak();
