82: ref.read(dailyQuizProvider.notifier).loadTodayQuiz();
83: 
84: // 🔥 STREAK CALCULATION — called every time the app opens:
85: final now = DateTime.now();
86: final authUser = ref.read(authProvider).asData?.value;
87: 
88: // 0. If user is authenticated, first try to sync progress FROM Firestore
89: //    so streak persists across reinstalls
90: final streakNotifier = ref.read(streakProvider.notifier);
91: if (authUser?.id.isNotEmpty == true) {
92: try {
93: final progressRepo = ref.read(progressRepositoryProvider);
94: final hiveProgress = progressRepo.getProgress();
95: // If Hive is empty or has no userId, fetch from Firestore
96: if (hiveProgress == null || hiveProgress.userId.isEmpty) {
97: await progressRepo.syncProgressFromFirestoreToHive(authUser!.id);
98: // Refresh the streak provider with restored data
99: streakNotifier.refresh();
100: }
101: } catch (_) {
102: // Silently handle Firestore fetch failure
103: }
104: }
105: 
106: // 0.5 Restore weekly activity from game_progress (Firebase-synced) to settings
107: //    so the weekly calendar survives cache clears
108: HiveService.restoreWeeklyActivityFromProgress();
109: 
110: 	// 1. Update HiveService weekly activity + last practice date FIRST
111: 	await HiveService.resetWeeklyActivityIfNewWeek();
112: 	await HiveService.markDayActive(now.weekday);
113: 	await HiveService.setLastPracticeDate(now);
114: 
115: 	// 2. Check if streak should increment (new day) or reset (missed >48h)
116: 	final newStreak = await streakNotifier.checkAndUpdateStreak();
117: 	
118: 	// 2.5 Check if weekly streak should update (new week)
119: 	await streakNotifier.checkAndUpdateWeeklyStreak();
120: 	
121: 	// 3. Record today as active (updates lastActiveDate, totalActiveDays)
122: 	await streakNotifier.recordActiveDay();
123: 
124: // 4. Handle streak freeze — if streak was reset to 1 and we have a freeze, restore it
125: if (newStreak == 1) {
126: final progress = ref.read(progressProvider).asData?.value;
127: final oldStreak = progress?.streakDays ?? 0;
128: if (oldStreak > 1) {
129: final hadFreeze = await HiveService.useStreakFreeze();
130: if (hadFreeze) {
131: // Restore the streak from before the reset
132: for (int i = 1; i < oldStreak; i++) {
133: await streakNotifier.incrementStreak();
134: }
135: }
136: }
137: }
138: 
139: // 4.5 Sync the final streak back to the main progress provider (Firestore 'progress' collection)
140: 
141: // if it wasn't refreshed yet use the one from service directly or 
142: await ref.read(progressProvider.notifier).syncStreak(ref.read(streakServiceProvider).getCurrentStreak());
143: 
144: // 5. Upload streak data to Firestore for persistent storage
145: if (authUser?.id.isNotEmpty == true) {
146: try {
147: final progressRepo = ref.read(progressRepositoryProvider);
148: var gameProgress = progressRepo.getProgress();
149: if (gameProgress != null) {
150: // Ensure progress has the correct userId before uploading
151: final uploadProgress = gameProgress.userId.isEmpty
152: ? gameProgress.copyWith(userId: authUser!.id)
153: : gameProgress;
154: await progressRepo.uploadProgressToFirestore(uploadProgress);
155: }
156: } catch (_) {
157: // Silently handle Firestore upload failure
158: }
159: }
160: 
161: // 6. Refresh ALL providers after streak updates
162: streakNotifier.refresh();
163: ref.read(progressProvider.notifier).fetchProgress();
164: });
165: }
