675: Widget _buildContinueLearningSection(
676: ThemeData theme, bool isDark, StudyPlanState studyState,
677: List<GrammarChapter> allGrammarChapters, List<VocabularyChapter> allVocabChapters,
678: LastOpenedChapter? lastOpened,
679: ) {
680: final items = studyState.items;
681: final grammarItems = items.where((i) => i.type == 'grammar').toList();
682: final vocabItems = items.where((i) => i.type == 'vocabulary').toList();
683: final grammarDone = grammarItems.where((i) => i.status == TodoStatus.completed).length;
684: final vocabDone = vocabItems.where((i) => i.status == TodoStatus.completed).length;
685: final grammarTotal = grammarItems.length;
686: final vocabTotal = vocabItems.length;
687: 
688: // 🔍 DEBUG: Log study plan state to help diagnose "All chapters completed" issue
689: print('📚 [ContinueLearning] items.length: ${items.length}');
690: print('📚 [ContinueLearning] nextGrammarId: ${studyState.nextGrammarId}');
691: print('📚 [ContinueLearning] nextVocabId: ${studyState.nextVocabId}');
692: print('📚 [ContinueLearning] lastOpened: $lastOpened');
693: print('📚 [ContinueLearning] grammarDone: $grammarDone / $grammarTotal');
694: print('📚 [ContinueLearning] vocabDone: $vocabDone / $vocabTotal');
695: 
696: GrammarChapter? findGrammar(int chapterNum) {
697: for (final c in allGrammarChapters) {
698: if (c.chapter == chapterNum) return c;
699: }
700: return null;
701: }
702: 
703: VocabularyChapter? findVocab(int chapterNum) {
704: for (final c in allVocabChapters) {
705: if (c.chapter == chapterNum) return c;
706: }
707: return null;
708: }
709: 
710: // Next pending items
711: TodoItem? findById(List<TodoItem> list, String? id) {
712: if (id == null) return null;
713: for (final item in list) {
714: if (item.id == id) return item;
715: }
716: return null;
717: }
718: 
719: // Resume: last opened chapter (if still pending), else next pending
720: TodoItem? resumeFromLastOpened(String type, String prefix) {
721: if (lastOpened == null) return null;
722: if (lastOpened.type != type) return null;
723: final item = findById(items, '${prefix}_${lastOpened.chapter}');
724: if (item != null && item.status == TodoStatus.pending) return item;
725: return null;
726: }
727: 
728: // Fallback: first pending of each type if no resume found
729: TodoItem? firstPendingGrammar;
730: for (var item in items) {
731: if (item.type == 'grammar' && item.status == TodoStatus.pending) {
732: firstPendingGrammar = item;
733: break;
734: }
735: }
736: TodoItem? firstPendingVocab;
737: for (var item in items) {
738: if (item.type == 'vocabulary' && item.status == TodoStatus.pending) {
739: firstPendingVocab = item;
740: break;
741: }
742: }
743: 
744: final resumeGrammar = resumeFromLastOpened('grammar', 'grammar')
745: ?? findById(items, studyState.nextGrammarId)
746: ?? firstPendingGrammar;
747: final resumeVocab = resumeFromLastOpened('vocabulary', 'vocab')
748: ?? findById(items, studyState.nextVocabId)
749: ?? firstPendingVocab;
750: 
751: // 🔍 DEBUG: Log what we resolved
752: print('📚 [ContinueLearning] resumeGrammar: ${resumeGrammar?.id ?? 'null'}');
753: print('📚 [ContinueLearning] resumeVocab: ${resumeVocab?.id ?? 'null'}');
754: print('📚 [ContinueLearning] firstPendingGrammar: ${firstPendingGrammar?.id ?? 'null'}');
755: print('📚 [ContinueLearning] firstPendingVocab: ${firstPendingVocab?.id ?? 'null'}');
756: 
757: final hasAny = resumeGrammar != null || resumeVocab != null;
758: 
759: return Column(
760: crossAxisAlignment: CrossAxisAlignment.start,
761: children: [
762: Row(
763: mainAxisAlignment: MainAxisAlignment.spaceBetween,
764: children: [
765: Flexible(
